package test.rice.obj;

import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Additional test cases for all PyObj classes.
 */
class PyObjTest {

    @Test
    void testPyIntObj() {
        PyIntObj i = new PyIntObj(42);
        assertEquals(42, i.getValue());
        assertEquals("42", i.toString());
        assertEquals(new PyIntObj(42), i);
        assertNotEquals(new PyIntObj(43), i);
        assertEquals(new PyIntObj(42).hashCode(), i.hashCode());
    }

    @Test
    void testPyFloatObj() {
        PyFloatObj f = new PyFloatObj(3.14);
        assertEquals(3.14, f.getValue());
        assertEquals("3.14", f.toString());
        assertEquals(new PyFloatObj(3.14), f);
        assertNotEquals(new PyFloatObj(2.71), f);
        assertEquals(new PyFloatObj(3.14).hashCode(), f.hashCode());
    }

    @Test
    void testPyBoolObj() {
        PyBoolObj trueObj = new PyBoolObj(true);
        PyBoolObj falseObj = new PyBoolObj(false);
        assertEquals(true, trueObj.getValue());
        assertEquals(false, falseObj.getValue());
        assertEquals("True", trueObj.toString());
        assertEquals("False", falseObj.toString());
        assertEquals(new PyBoolObj(true), trueObj);
        assertNotEquals(trueObj, falseObj);
    }

    @Test
    void testPyCharObj() {
        PyCharObj c = new PyCharObj('a');
        assertEquals('a', c.getValue());
        assertEquals("'a'", c.toString());
        assertEquals(new PyCharObj('a'), c);
        assertNotEquals(new PyCharObj('b'), c);
    }

    @Test
    void testEqualsDifferentTypes() {
        PyIntObj i = new PyIntObj(1);
        PyFloatObj f = new PyFloatObj(1.0);
        assertNotEquals(i, f);
        assertNotEquals(f, i);
    }

    @Test
    void testPyStringObjEquals() {
        PyStringObj s1 = new PyStringObj("hello");
        PyStringObj s2 = new PyStringObj("hello");
        PyStringObj s3 = new PyStringObj("world");
        assertEquals(s1, s2);
        assertNotEquals(s1, s3);
        assertEquals(s1.hashCode(), s2.hashCode());
    }

    @Test
    void testPyDictObjEquals() {
        Map<PyIntObj, PyStringObj> m1 = new LinkedHashMap<>();
        m1.put(new PyIntObj(1), new PyStringObj("a"));
        PyDictObj<PyIntObj, PyStringObj> d1 = new PyDictObj<>(m1);

        Map<PyIntObj, PyStringObj> m2 = new LinkedHashMap<>();
        m2.put(new PyIntObj(1), new PyStringObj("a"));
        PyDictObj<PyIntObj, PyStringObj> d2 = new PyDictObj<>(m2);

        Map<PyIntObj, PyStringObj> m3 = new LinkedHashMap<>();
        m3.put(new PyIntObj(1), new PyStringObj("b"));
        PyDictObj<PyIntObj, PyStringObj> d3 = new PyDictObj<>(m3);

        assertEquals(d1, d2);
        assertNotEquals(d1, d3);
        assertEquals(d1.hashCode(), d2.hashCode());
    }
}

package main.rice.obj;

import java.util.List;

/**
 * List objects.
 * @param <E> the type of elements in the list.
 */
public class PyListObj<E extends APyObj<?>> extends AIterablePyObj<List<E>> {

    /**
     * Constructor for PyListObj.
     * @param value the underlying Java List of elements.
     */
    public PyListObj(List<E> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return the list surrounded by square brackets.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < this.value.size(); i++) {
            sb.append(this.value.get(i).toString());
            if (i < this.value.size() - 1) {
                sb.append(", ");
            }
        }
        sb.append("]");
        return sb.toString();
    }
}

package main.rice.obj;

import java.util.Objects;

/**
 * Abstract base class for all Python objects.
 * @param <T> the type of the underlying Java value.
 */
public abstract class APyObj<T> {

    /**
     * The underlying Java value.
     */
    protected T value;

    /**
     * Returns the underlying Java value.
     * @return the underlying Java value.
     */
    public T getValue() {
        return this.value;
    }

    /**
     * Returns a Python-style string representation of this object.
     * @return a Python-style string representation.
     */
    @Override
    public abstract String toString();

    /**
     * Checks if this object is equal to another object.
     * Two APyObj instances are equal if they have the same type AND equal values.
     * @param obj the object to compare to.
     * @return true if equal, false otherwise.
     */
    @Override
    public boolean equals(Object obj) {
        if (this == obj) {
            return true;
        }
        if (obj == null || this.getClass() != obj.getClass()) {
            return false;
        }
        APyObj<?> other = (APyObj<?>) obj;
        return Objects.equals(this.value, other.value);
    }

    /**
     * Returns a hash code for this object.
     * @return a hash code.
     */
    @Override
    public int hashCode() {
        return Objects.hash(this.getClass(), this.value);
    }
}

