package main.rice.obj;

/**
 * Abstract base for iterable objects.
 * @param <T> the type of the underlying collection.
 */
public abstract class AIterablePyObj<T> extends APyObj<T> {
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * String objects.
 */
public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {

    /**
     * Constructor for PyStringObj.
     * @param value the underlying Java String value.
     */
    public PyStringObj(String value) {
        this.value = new ArrayList<>();
        for (char c : value.toCharArray()) {
            this.value.add(new PyCharObj(c));
        }
    }

    /**
     * Returns a Python-style string representation.
     * @return the string surrounded by single quotes.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("'");
        for (PyCharObj c : this.value) {
            // Note: PyCharObj.getValue() returns the Character.
            // We don't want the quotes from PyCharObj.toString().
            sb.append(c.getValue());
        }
        sb.append("'");
        return sb.toString();
    }
}

