package main.rice.obj;

import java.util.Iterator;
import java.util.Set;

/**
 * Set objects.
 * @param <E> the type of elements in the set.
 */
public class PySetObj<E extends APyObj<?>> extends AIterablePyObj<Set<E>> {

    /**
     * Constructor for PySetObj.
     * @param value the underlying Java Set of elements.
     */
    public PySetObj(Set<E> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return "set()" if empty, or the set elements surrounded by curly braces.
     */
    @Override
    public String toString() {
        if (this.value.isEmpty()) {
            return "set()";
        }
        StringBuilder sb = new StringBuilder("{");
        Iterator<E> it = this.value.iterator();
        while (it.hasNext()) {
            sb.append(it.next().toString());
            if (it.hasNext()) {
                sb.append(", ");
            }
        }
        sb.append("}");
        return sb.toString();
    }
}

package main.rice.obj;

/**
 * Boolean objects (True/False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    /**
     * Constructor for PyBoolObj.
     * @param value the underlying Java Boolean value.
     */
    public PyBoolObj(Boolean value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return "True" or "False".
     */
    @Override
    public String toString() {
        return this.value ? "True" : "False";
    }
}

package main.rice.obj;

import java.util.List;

/**
 * Tuple objects.
 * @param <E> the type of elements in the tuple.
 */
public class PyTupleObj<E extends APyObj<?>> extends AIterablePyObj<List<E>> {

    /**
     * Constructor for PyTupleObj.
     * @param value the underlying Java List of elements.
     */
    public PyTupleObj(List<E> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return the tuple surrounded by parentheses.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("(");
        for (int i = 0; i < this.value.size(); i++) {
            sb.append(this.value.get(i).toString());
            if (i < this.value.size() - 1) {
                sb.append(", ");
            }
        }
        if (this.value.size() == 1) {
            sb.append(",");
        }
        sb.append(")");
        return sb.toString();
    }
}

