package main.rice.obj;

import java.util.Iterator;
import java.util.Map;

/**
 * Dictionary objects.
 * @param <K> the type of keys in the dict.
 * @param <V> the type of values in the dict.
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends AIterablePyObj<Map<K, V>> {

    /**
     * Constructor for PyDictObj.
     * @param value the underlying Java Map of key-value pairs.
     */
    public PyDictObj(Map<K, V> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return the dict surrounded by curly braces with key: value pairs.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("{");
        Iterator<Map.Entry<K, V>> it = this.value.entrySet().iterator();
        while (it.hasNext()) {
            Map.Entry<K, V> entry = it.next();
            sb.append(entry.getKey().toString());
            sb.append(": ");
            sb.append(entry.getValue().toString());
            if (it.hasNext()) {
                sb.append(", ");
            }
        }
        sb.append("}");
        return sb.toString();
    }
}

